# Flatten fee json
def walk(obj, path=()):
    out = []
    if isinstance(obj, dict):
        out.append((path, obj))
        for k, v in obj.items():
            out.extend(walk(v, path + (str(k),)))
    elif isinstance(obj, list):
        for i, v in enumerate(obj):
            out.extend(walk(v, path + (str(i),)))
    return out

nodes = walk(fees)

def fee_for(scheme, aci, amount):
    scheme = str(scheme).lower()
    aci = str(aci).lower()
    best = None
    for path, leaf in nodes:
        pstr = ' '.join(path).lower()
        if scheme not in pstr or aci not in pstr or not isinstance(leaf, dict):
            continue
        fixed = 0.0
        pct = 0.0
        nums = []
        for k, v in leaf.items():
            if isinstance(v, (int, float)):
                nums.append((str(k).lower(), float(v)))
        for k, v in nums:
            if any(x in k for x in ['fixed','flat']):
                fixed = v
            elif any(x in k for x in ['percent','rate','bps','basis']):
                pct = v
        if pct > 1:
            pct = pct / 100.0
        fee = fixed + amount * pct
        if best is None or fee < best:
            best = fee
    return best

# Candidate ACIs from fee paths
results = []
for scheme, g in p.groupby(scheme_col):
    total_amount = pd.to_numeric(g[amount_col], errors='coerce').fillna(0).sum()
    candidates = set(map(str, g[aci_col].dropna().unique()))
    for path, _ in nodes:
        if str(scheme).lower() in ' '.join(path).lower():
            for token in path:
                tok = str(token)
                if re.fullmatch(r'[A-Za-z0-9]{1,3}', tok):
                    candidates.add(tok)
    for aci in candidates:
        fee = fee_for(scheme, aci, total_amount)
        if fee is not None:
            results.append((scheme, aci, fee))

if not results:
    print('SIB_SUBMIT')
    print('Not Applicable')
else:
    best = min(results, key=lambda x: x[2])
    print('SIB_SUBMIT')
